// Normalizes the app's POST body into the exact flat shape the Parse node
// already expects (Type / Background / content / assets + an `id`).
// This is why the Parse node below needs ZERO changes.

const b = $json.body || $json;

let assets = b.assets;
if (Array.isArray(assets)) {
  assets = assets.filter(Boolean);
} else if (typeof assets === 'string' && assets.trim()) {
  assets = assets.split(',').map(function (s) { return s.trim(); }).filter(Boolean);
} else {
  assets = [];
}

// `manual-` prefix is the flag the "Manual run?" IF node checks later.
return [{ json: {
  id: 'manual-' + Date.now(),
  Type: b.type || b.Type || 'text',
  Background: b.background || b.Background || 'teal',
  content: b.content || b.Content || '',
  assets: assets
}}];

// Factors social-render — reads Notion Type + Background dropdowns (Simplify ON)
// Type -> template ; Background -> variant color ; assets -> images (engine classifies)

const TEMPLATE_BASE_URL = "https://factors-templates.small-band-469e.workers.dev";

// Type dropdown -> template file + default format
const TYPE_MAP = {
  text:        { tpl:"quote",       w:1080, h:1080 },
  quote:       { tpl:"quote",       w:1080, h:1080 },
  stat:        { tpl:"stat",        w:1080, h:1080 },
  testimonial: { tpl:"testimonial", w:1920, h:1080 },
  illustration:{ tpl:"illustration",w:1080, h:1080 },
  "creative-billboard":{ tpl:"creative-billboard", w:1080, h:1080 },
  "billboard-wide":{ tpl:"billboard-wide", w:1600, h:1080 },
};
const VARIANTS = ["red","teal","amber","green","orange","blue","paper"];

// read flat fields (Simplify ON). Falls back across naming styles.
function prop(name){
  let v = $json[name];
  if (v == null) v = $json["property_" + name];
  if (v == null) v = $json["property_" + name.toLowerCase()];
  if (v == null) return "";
  if (Array.isArray(v)) return v;
  return v;
}

const typeRaw = String(prop("Type") || prop("type") || "text").toLowerCase().trim();
const bgRaw   = String(prop("Background") || prop("background") || "teal").toLowerCase().trim();
const contentRaw = String(prop("content") || prop("Content") || "");
let assets = prop("assets"); if(!Array.isArray(assets)) assets = prop("Assets"); if(!Array.isArray(assets)) assets = assets?[assets]:[];

const t = TYPE_MAP[typeRaw] || TYPE_MAP.text;
const variant = VARIANTS.indexOf(bgRaw) >= 0 ? bgRaw : "teal";
const w = t.w, h = t.h;

// parse content: first non-key line(s) = body; "key: value" lines fill fields
const fields = { body:"", underline:"", eyebrow:"", stat:"", stat_label:"", name:"", role:"", footer:"www.factors.ai" };
const KEYS = { underline:"underline", eyebrow:"eyebrow", stat:"stat", label:"stat_label",
               name:"name", role:"role", cta:"footer", footer:"footer" };
let bodyLines=[];
String(contentRaw).split("\n").forEach(function(line){
  const m = line.match(/^\s*([a-zA-Z ]+):\s*(.+)$/);
  if (m && KEYS[m[1].trim().toLowerCase()]) fields[KEYS[m[1].trim().toLowerCase()]] = m[2].trim();
  else if (line.trim()) bodyLines.push(line.trim());
});
fields.body = bodyLines.join(" ");
if (fields.underline && fields.body.indexOf(fields.underline) < 0) fields.underline = "";

// build query string (no URLSearchParams in the sandbox)
function enc(v){ return encodeURIComponent(v==null?"":String(v)); }
const params = {
  variant:variant, w:String(w), h:String(h),
  body:fields.body, underline:fields.underline, eyebrow:fields.eyebrow,
  stat:fields.stat, stat_label:fields.stat_label, foot:fields.footer,
  name:fields.name, role:fields.role,
  assets: assets.join(","),        // testimonial: engine classifies headshot vs logos
  partner: assets[0] || ""         // back-compat
};
let qs=[]; for (const k in params){ qs.push(enc(k)+"="+enc(params[k])); }
const renderUrl = TEMPLATE_BASE_URL + "/" + t.tpl + ".html?" + qs.join("&");

const browserless = {
  url: renderUrl, options:{ type:"png", fullPage:false },
  viewport:{ width:w, height:h, deviceScaleFactor:2 },
  gotoOptions:{ waitUntil:"networkidle0" }
};

const pageId = $json.id || $json.pageId;
const imgKey = (String(pageId) + "-" + Date.now() + ".png").replace(/[^a-zA-Z0-9._-]/g,"_");

return [{ json: {
  pageId:pageId, type:typeRaw, template:t.tpl, variant:variant, w:w, h:h,
  fields:fields, renderUrl:renderUrl, browserless:browserless, imgKey:imgKey
}}];
